const r = $input.first().json;
const totalExec = Number(r.exec_total) || 0;
const totalSucces = Number(r.exec_succes) || 0;

return [{ json: { success: true, data: { stats: {
  totalAutomations: Number(r.total_catalog) || 0,
  actives: Number(r.actives) || 0,
  executionsToday: totalExec,
  tauxReussite: totalExec > 0 ? Math.round((totalSucces / totalExec) * 100) : 0,
  erreurs24h: Number(r.exec_erreurs) || 0
} } } }];
